const formatCurrency = (amount: number) =>
  new Intl.NumberFormat("es-CR", {
    style: "currency",
    currency: "CRC",
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(amount);

function getStatusFill(status: LotData["status"], isSelected: boolean, isHovered: boolean) {
  if (isSelected) return "rgba(116,206,82,0.75)";
  switch (status) {
    case "available":
      return isHovered ? "rgba(116,206,82,0.45)" : "rgba(116,206,82,0.18)";
    case "sold":
      return "rgba(239,68,68,0.45)";
    case "reserved":
      return "rgba(245,158,11,0.45)";
    case "not_available":
      return "rgba(100,116,139,0.22)";
    default:
      return "rgba(116,206,82,0.18)";
  }
}

function getStatusStroke(status: LotData["status"], isSelected: boolean) {
  if (isSelected) return "#74CE52";
  switch (status) {
    case "available": return "rgba(116,206,82,0.7)";
    case "sold":      return "rgba(239,68,68,0.7)";
    case "reserved":  return "rgba(245,158,11,0.7)";
    default:          return "rgba(100,116,139,0.4)";
  }
}

export default function LotMapInteractive({ lots, selectedLot, onLotSelect }: LotMapInteractiveProps) {
  const [hoveredId, setHoveredId] = useState<number | null>(null);
  const [tooltip, setTooltip] = useState<TooltipState>({ visible: false, x: 0, y: 0, lot: null });
  const svgRef = useRef<SVGSVGElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const lotsById = Object.fromEntries(lots.map((l) => [l.id, l]));

  const handleMouseMove = useCallback((e: React.MouseEvent, lot: LotData) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    setTooltip({ visible: true, x: e.clientX - rect.left, y: e.clientY - rect.top, lot });
  }, []);

  const handleMouseEnter = useCallback((id: number) => setHoveredId(id), []);

  const handleMouseLeave = useCallback(() => {
    setHoveredId(null);
    setTooltip((prev) => ({ ...prev, visible: false }));
  }, []);

  const handleClick = useCallback((lot: LotData) => {
    if (lot.status !== "available") return;
    onLotSelect(selectedLot?.id === lot.id ? null : lot);
  }, [selectedLot, onLotSelect]);

  return (
    <div ref={containerRef} className="relative w-full select-none">
      <svg
        ref={svgRef}
        viewBox="0 -277 1756.15 2402"
        className="w-full h-auto block rounded-xl"
        style={{ backgroundColor: "#0a0f0b" }}
        xmlns="http://www.w3.org/2000/svg"
      >
        <defs>
          <pattern id="grid" width="100" height="100" patternUnits="userSpaceOnUse">
            <path d="M 100 0 L 0 0 0 100" fill="none" stroke="rgba(116,206,82,0.05)" strokeWidth="1"/>
          </pattern>
          {/* Path for CARRETERA PRINCIPAL text */}
          <path id="path-carretera" d="M 540 88 L 1720 100"/>
        </defs>

        {/* Background grid */}
        <rect x="0" y="0" width="1756.15" height="1848.47" fill="url(#grid)" />

        {/* ── ASFALTO — renderizado ANTES de los lotes para que quede debajo ── */}
        {/* cls-6: shape principal de la calle del SVG original */}
        <path
          d={STREET_PATH}
          fill="#2a2a2a"
          stroke="#4a4a4a"
          strokeWidth="1.5"
          style={{ pointerEvents: "none" }}
        />
        {/* Segundo path de refuerzo (gaps entre lotes) */}
        <path
          d={STREET_PATH2}
          fill="#2a2a2a"
          stroke="#4a4a4a"
          strokeWidth="1.5"
          fillRule="evenodd"
          style={{ pointerEvents: "none" }}
        />

        {/* ── LOTES ── */}
        {Object.entries(LOT_POLYGONS).map(([idStr, points]) => {
          const id = Number(idStr);
          const lot = lotsById[id];
          if (!lot) return null;
          const isSelected = selectedLot?.id === id;
          const isHovered = hoveredId === id;
          const isClickable = lot.status === "available";
          return (
            <polygon
              key={id}
              points={points}
              fill={getStatusFill(lot.status, isSelected, isHovered)}
              stroke={getStatusStroke(lot.status, isSelected)}
              strokeWidth={isSelected ? 8 : 3}
              strokeLinejoin="round"
              style={{ cursor: isClickable ? "pointer" : "default", transition: "fill 0.15s" }}
              onMouseEnter={() => handleMouseEnter(id)}
              onMouseLeave={handleMouseLeave}
              onMouseMove={(e) => handleMouseMove(e, lot)}
              onClick={() => handleClick(lot)}
            />
          );
        })}

        {/* ── ETIQUETAS DE LOTE ── */}
        {Object.entries(LOT_POLYGONS).map(([idStr]) => {
          const id = Number(idStr);
          const lot = lotsById[id];
          if (!lot) return null;
          const [lx, ly] = LOT_LABELS[id];
          const isSelected = selectedLot?.id === id;
          return (
            <text
              key={`label-${id}`}
              transform={`translate(${lx}, ${ly}) rotate(7)`}
              x="0"
              y="0"
              textAnchor="middle"
              fontSize="26"
              fontWeight={isSelected ? "700" : "600"}
              fontFamily="'Inter', system-ui, sans-serif"
              fill={isSelected ? "#74CE52" : "rgba(255,255,255,0.85)"}
              style={{ pointerEvents: "none", userSelect: "none" }}
            >
              {id}
            </text>
          );
        })}

        {/* ── CARRETERA PRINCIPAL ── */}
        <text
          fontFamily="'Inter', system-ui, sans-serif"
          fontSize="22"
          fontWeight="700"
          letterSpacing="8"
          fill="rgba(255,255,255,0.85)"
          style={{ pointerEvents: "none", textTransform: "uppercase" }}
        >
          <textPath href="#path-carretera" startOffset="50%" textAnchor="middle">
            CARRETERA PRINCIPAL
          </textPath>
        </text>
      </svg>

      {/* Tooltip */}
      {tooltip.visible && tooltip.lot && (
        <div
          className="absolute z-20 pointer-events-none rounded-xl shadow-2xl p-3 text-sm min-w-[160px]"
          style={{
            left: tooltip.x + 14,
            top: tooltip.y - 10,
            transform: tooltip.x > 550 ? "translateX(-110%)" : undefined,
            backgroundColor: "#111a14",
            border: "1px solid rgba(116,206,82,0.2)",
          }}
        >
          <div className="font-bold text-white text-base mb-1">Lote {tooltip.lot.id}</div>
          <div style={{ color: "rgba(255,255,255,0.6)" }}>{tooltip.lot.size.toLocaleString("es-CR")} m²</div>
          {tooltip.lot.status === "available" ? (
            <>
              <div className="text-xs mt-0.5" style={{ color: "rgba(255,255,255,0.4)" }}>{formatCurrency(tooltip.lot.pricePerM2)}/m²</div>
              <div className="font-semibold mt-1" style={{ color: "#74CE52" }}>{formatCurrency(tooltip.lot.total)}</div>
              <div className="text-xs mt-1 font-medium" style={{ color: "#74CE52" }}>Disponible ✓</div>
            </>
          ) : (
            <div className={`text-xs font-medium mt-1 ${
              tooltip.lot.status === "sold" ? "text-red-400" :
              tooltip.lot.status === "reserved" ? "text-amber-400" :
              "text-white/40"
            }`}>
              {tooltip.lot.status === "sold" ? "Vendido" :
               tooltip.lot.status === "reserved" ? "Reservado" : "No disponible"}
            </div>
          )}
        </div>
      )}

      {/* Leyenda */}
      <div className="flex flex-wrap gap-3 mt-3 px-1">
        {[
          { color: "rgba(116,206,82,0.4)", border: "rgba(116,206,82,0.7)", label: "Disponible" },
          { color: "rgba(245,158,11,0.4)", border: "rgba(245,158,11,0.7)", label: "Reservado" },
          { color: "rgba(239,68,68,0.4)", border: "rgba(239,68,68,0.7)", label: "Vendido" },
          { color: "rgba(100,116,139,0.3)", border: "rgba(100,116,139,0.5)", label: "No disponible" },
        ].map(({ color, border, label }) => (
          <div key={label} className="flex items-center gap-1.5 text-xs" style={{ color: "rgba(255,255,255,0.5)" }}>
            <span className="w-3.5 h-3.5 rounded-sm inline-block flex-shrink-0" style={{ backgroundColor: color, border: `1px solid ${border}` }} />
            {label}
          </div>
        ))}
        <div className="flex items-center gap-1.5 text-xs ml-2" style={{ color: "rgba(255,255,255,0.3)" }}>
          <span className="inline-block w-5 h-2 rounded-sm" style={{ backgroundColor: "#2a2a2a", border: "1px solid #4a4a4a" }} />
          Calle
        </div>
      </div>
    </div>
  );
}
